-- Generated from src/data/territory-tracker-realtors.json
-- Marketplace reads from "ZipInventory", not "TerritoryTrackerEntry".
-- Tier mapping used here: PREMIER -> PREMIUM ($1,500), STANDARD -> STANDARD ($500), RURAL -> STANDARD ($500).

ON CONFLICT ("zipCode", "vertical") DO UPDATE
SET
  "state" = EXCLUDED."state",
  "city" = EXCLUDED."city",
  "county" = EXCLUDED."county",
  "tier" = EXCLUDED."tier",
  "annualPriceCents" = EXCLUDED."annualPriceCents",
  "status" = EXCLUDED."status",
  "updatedAt" = CURRENT_TIMESTAMP;
